solution_code:
#include <iostream>

int square(int n) {
    return n * n;
}

int main() {
    std::cout << (square(0)   == 0   ? "PASS" : "FAIL") << '\n';
    std::cout << (square(3)   == 9   ? "PASS" : "FAIL") << '\n';
    std::cout << (square(-4)  == 16  ? "PASS" : "FAIL") << '\n';
    std::cout << (square(10)  == 100 ? "PASS" : "FAIL") << '\n';
    return 0;
}

