#include <iostream>

bool isPositive(int n) {
    return n > 0;
}

int main() {
    std::cout << (isPositive(1)    == true  ? "PASS" : "FAIL") << '\n';
    std::cout << (isPositive(0)    == false ? "PASS" : "FAIL") << '\n';
    std::cout << (isPositive(-5)   == false ? "PASS" : "FAIL") << '\n';
    std::cout << (isPositive(100)  == true  ? "PASS" : "FAIL") << '\n';
